class EncodingKind(enum.Enum):
    
    RAW = 0
    
    CBOR = 1
    
    JSON = 2
    
    CUSTOM = 3
    


class _UniffiFfiConverterTypeEncodingKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return EncodingKind.RAW
        if variant == 2:
            return EncodingKind.CBOR
        if variant == 3:
            return EncodingKind.JSON
        if variant == 4:
            return EncodingKind.CUSTOM
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == EncodingKind.RAW:
            return
        if value == EncodingKind.CBOR:
            return
        if value == EncodingKind.JSON:
            return
        if value == EncodingKind.CUSTOM:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == EncodingKind.RAW:
            buf.write_i32(1)
        if value == EncodingKind.CBOR:
            buf.write_i32(2)
        if value == EncodingKind.JSON:
            buf.write_i32(3)
        if value == EncodingKind.CUSTOM:
            buf.write_i32(4)



