        if isinstance(value, ProllyBindingError.Store):
            buf.write_i32(6)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, ProllyBindingError.Serialization):
            buf.write_i32(7)
            _UniffiFfiConverterString.write(value.reason, buf)
        if isinstance(value, ProllyBindingError.Internal):
            buf.write_i32(8)
            _UniffiFfiConverterString.write(value.reason, buf)


