class MutationKind(enum.Enum):
    
    UPSERT = 0
    
    DELETE = 1
    


class _UniffiFfiConverterTypeMutationKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return MutationKind.UPSERT
        if variant == 2:
            return MutationKind.DELETE
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == MutationKind.UPSERT:
            return
        if value == MutationKind.DELETE:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == MutationKind.UPSERT:
            buf.write_i32(1)
        if value == MutationKind.DELETE:
            buf.write_i32(2)



