class NamedRootRetentionKind(enum.Enum):
    
    ALL = 0
    
    EXACT = 1
    
    PREFIX = 2
    
    NEWEST_BY_NAME = 3
    
    UPDATED_SINCE = 4
    


class _UniffiFfiConverterTypeNamedRootRetentionKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return NamedRootRetentionKind.ALL
        if variant == 2:
            return NamedRootRetentionKind.EXACT
        if variant == 3:
            return NamedRootRetentionKind.PREFIX
        if variant == 4:
            return NamedRootRetentionKind.NEWEST_BY_NAME
        if variant == 5:
            return NamedRootRetentionKind.UPDATED_SINCE
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == NamedRootRetentionKind.ALL:
            return
        if value == NamedRootRetentionKind.EXACT:
            return
        if value == NamedRootRetentionKind.PREFIX:
            return
        if value == NamedRootRetentionKind.NEWEST_BY_NAME:
            return
        if value == NamedRootRetentionKind.UPDATED_SINCE:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == NamedRootRetentionKind.ALL:
            buf.write_i32(1)
        if value == NamedRootRetentionKind.EXACT:
            buf.write_i32(2)
        if value == NamedRootRetentionKind.PREFIX:
            buf.write_i32(3)
        if value == NamedRootRetentionKind.NEWEST_BY_NAME:
            buf.write_i32(4)
        if value == NamedRootRetentionKind.UPDATED_SINCE:
            buf.write_i32(5)



