class ResolutionKind(enum.Enum):
    
    VALUE = 0
    
    DELETE = 1
    
    UNRESOLVED = 2
    


class _UniffiFfiConverterTypeResolutionKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return ResolutionKind.VALUE
        if variant == 2:
            return ResolutionKind.DELETE
        if variant == 3:
            return ResolutionKind.UNRESOLVED
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == ResolutionKind.VALUE:
            return
        if value == ResolutionKind.DELETE:
            return
        if value == ResolutionKind.UNRESOLVED:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == ResolutionKind.VALUE:
            buf.write_i32(1)
        if value == ResolutionKind.DELETE:
            buf.write_i32(2)
        if value == ResolutionKind.UNRESOLVED:
            buf.write_i32(3)



