class SnapshotNamespaceKind(enum.Enum):
    
    BRANCH = 0
    
    TAG = 1
    
    CHECKPOINT = 2
    
    CUSTOM = 3
    


class _UniffiFfiConverterTypeSnapshotNamespaceKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return SnapshotNamespaceKind.BRANCH
        if variant == 2:
            return SnapshotNamespaceKind.TAG
        if variant == 3:
            return SnapshotNamespaceKind.CHECKPOINT
        if variant == 4:
            return SnapshotNamespaceKind.CUSTOM
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == SnapshotNamespaceKind.BRANCH:
            return
        if value == SnapshotNamespaceKind.TAG:
            return
        if value == SnapshotNamespaceKind.CHECKPOINT:
            return
        if value == SnapshotNamespaceKind.CUSTOM:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == SnapshotNamespaceKind.BRANCH:
            buf.write_i32(1)
        if value == SnapshotNamespaceKind.TAG:
            buf.write_i32(2)
        if value == SnapshotNamespaceKind.CHECKPOINT:
            buf.write_i32(3)
        if value == SnapshotNamespaceKind.CUSTOM:
            buf.write_i32(4)



