class ValueRefKind(enum.Enum):
    
    INLINE = 0
    
    BLOB = 1
    


class _UniffiFfiConverterTypeValueRefKind(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return ValueRefKind.INLINE
        if variant == 2:
            return ValueRefKind.BLOB
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if value == ValueRefKind.INLINE:
            return
        if value == ValueRefKind.BLOB:
            return
        raise ValueError(value)

    @staticmethod
    def write(value, buf):
        if value == ValueRefKind.INLINE:
            buf.write_i32(1)
        if value == ValueRefKind.BLOB:
            buf.write_i32(2)



class _UniffiFfiConverterOptionalTypeBlobRefRecord(_UniffiConverterRustBuffer):
    @classmethod
    def check_lower(cls, value):
        if value is not None:
            _UniffiFfiConverterTypeBlobRefRecord.check_lower(value)

    @classmethod
    def write(cls, value, buf):
        if value is None:
            buf.write_u8(0)
            return

        buf.write_u8(1)
        _UniffiFfiConverterTypeBlobRefRecord.write(value, buf)

    @classmethod
    def read(cls, buf):
        flag = buf.read_u8()
        if flag == 0:
            return None
        elif flag == 1:
            return _UniffiFfiConverterTypeBlobRefRecord.read(buf)
        else:
            raise InternalError("Unexpected flag byte for optional type")

