class _UniffiFfiConverterTypeProllyEngine:
    @staticmethod
    def lift(value: int) -> ProllyEngine:
        return ProllyEngine._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: ProllyEngine):
        if not isinstance(value, ProllyEngine):
            raise TypeError("Expected ProllyEngine instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: ProllyEngine) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> ProllyEngine:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: ProllyEngine, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))


